import{createDesmosGraphs,desmosColors,getColorLatexExpressions,getDesmosSlider}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({voxels:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.59,-.71,-.38,.6,-.7,.38,-.54,0,.84]},bounds:{xmin:-1.25,xmax:1.25,ymin:-1.25,ymax:1.25,zmin:-1.25,zmax:1.25},expressions:[{latex:raw`f(x, y, z) = \frac{1}{1.5} x + y + z`,hidden:!0},...getDesmosSlider({expression:"n = 8",min:4,max:16,step:1,secret:!1}),{latex:raw`X = [(i, j) \for i = [-1 + \frac{1}{n}, -1 + \frac{3}{n}, ..., 1 - \frac{1}{n}], j = [-1 + \frac{1}{n}, -1 + \frac{3}{n}, ..., 1 - \frac{1}{n}]]`,hidden:!0,secret:!0},{latex:raw`N(x) = \frac{2}{n}(\round(\frac{n}{2}x + \frac{\mod(n, 2)}{2}) - \frac{\mod(n, 2)}{2})`,hidden:!0,secret:!0},{latex:raw`N_f(x) = \frac{2}{n}(\round(\frac{n}{2}x + \frac{1 - \mod(n, 2)}{2}) - \frac{1 - \mod(n, 2)}{2})`,hidden:!0,secret:!0},{latex:raw`\left|z\right| \leq N(\sqrt{1 - X.x^2 - X.y^2}) \{X.x - \frac{1}{n} \leq x \leq X.x + \frac{1}{n}\} \{X.y - \frac{1}{n} \leq y \leq X.y + \frac{1}{n}\} \{ \left|X\right| < 1 \}`,colorLatex:"C",secret:!0},{latex:raw`f_R(x, y, z) = f(N_f(x), N_f(y), N_f(z))`,hidden:!0,secret:!0},{latex:raw`P(x, y, z) = e^{-f_R(x, y, z)^2}`,secret:!0},{latex:raw`R(x, y, z) = \{ f_R(x, y, z) \geq 0 : 1 - P(x, y, z), f_R(x, y, z) < 0: 0 \}`,secret:!0},{latex:raw`B(x, y, z) = \{ f_R(x, y, z) \leq 0 : 1 - P(x, y, z), f_R(x, y, z) > 0: 0 \}`,secret:!0},{latex:raw`C = \rgb(204R(x, y, z) + 40B(x, y, z) + 122P(x, y, z), 40R(x, y, z) + 122B(x, y, z) + 40P(x, y, z), 40R(x, y, z) + 204B(x, y, z) + 205P(x, y, z))`,secret:!0}]},chunkRegion:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.72,-.66,-.19,.64,-.75,.17,-.26,0,.97]},bounds:{xmin:-1.25,xmax:1.25,ymin:-1.25,ymax:1.25,zmin:-1.25,zmax:1.25},expressions:[{latex:raw`f(x, y, z) = 1.25(z + x - 0.25)`,hidden:!0,secret:!0},{latex:raw`x^3 - 1 \leq z \leq y - x^3 \{ x \geq 0 \} \{ y \leq 1 \}`,colorLatex:"C"},...getColorLatexExpressions()]},parabolaRegion:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.78,-.54,-.32,.49,-.84,.21,-.38,0,.92]},bounds:{xmin:-1.25,xmax:1.25,ymin:-1.25,ymax:1.25,zmin:-1.25,zmax:1.25},expressions:[{latex:raw`f(x, y, z) = z - 2y`,hidden:!0},{latex:raw`x^2 + y \leq z \leq 1 \{y \geq 0\}`,colorLatex:"C"},...getColorLatexExpressions()]},slicedCylinder:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.58,-.81,-.13,.79,-.59,.18,-.22,0,.98]},bounds:{xmin:-5,xmax:5,ymin:-5,ymax:5,zmin:-3.15,zmax:6.85},expressions:[{latex:raw`f(x, y, z) = \frac{1}{4}(z + y)`,hidden:!0,secret:!0},{latex:raw`x - 1 \leq z \leq 6 - x^2 - y^2 \{ x^2 + y^2 \leq 4 \}`,colorLatex:"C"},...getColorLatexExpressions()]},cylindricalCoordinates:{use3d:!0,options:{showPlane3D:!1,worldRotation3D:[-.81,.5,-.29,-.47,-.86,-.17,-.34,0,.94]},bounds:{xmin:-2,xmax:2,ymin:-2,ymax:2,zmin:-2,zmax:2},expressions:[...getDesmosSlider({expression:"r_0 = 1",min:0,max:2,secret:!1}),...getDesmosSlider({expression:"\\theta_0 = 1",min:0,max:"2\\pi",secret:!1}),...getDesmosSlider({expression:"z_0 = 1",min:-2,max:2,secret:!1}),{latex:raw`(r_0\cos(\theta_0), r_0\sin(\theta_0), z_0)`,color:desmosColors.purple},{latex:raw`(0, 0, 0), (r_0\cos(\theta_0), r_0\sin(\theta_0), 0)`,color:desmosColors.blue,points:!1,lines:!0,secret:!0},{latex:raw`(r_0\cos(\theta_0), r_0\sin(\theta_0), 0), (r_0\cos(\theta_0), r_0\sin(\theta_0), z_0)`,color:desmosColors.red,points:!1,lines:!0,secret:!0}]},cylindricalGraphs:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-4,xmax:4,ymin:-4,ymax:4,zmin:-4,zmax:4},expressions:[{latex:raw`r = 3`,color:desmosColors.purple,hidden:!0},{latex:raw`\arctan(y, x) = \frac{\pi}{4}`,color:desmosColors.blue,hidden:!0},{latex:raw`z = 1`,color:desmosColors.red,hidden:!0}]}})}